mapper.select:
SELECT id, name, partner_id, invoice_date, due_date, state, company_id, amount_untaxed, amount_tax, amount_total, origin_ref, payment_ref, payment_state, create_uid, create_date, write_uid, write_date FROM account_invoice
AND ( name ILIKE CONCAT('%', #{query.keyword}, '%') OR origin_ref ILIKE CONCAT('%', #{query.keyword}, '%') OR payment_ref ILIKE CONCAT('%', #{query.keyword}, '%') )
AND partner_id = #{query.partnerId}
AND state = #{query.state}
AND payment_state = #{query.paymentState}
AND invoice_date = #{query.invoiceDate}
AND due_date = #{query.dueDate}
ORDER BY id DESC
